from flask import Flask, request, session, redirect, url_for
import requests

app = Flask(__name__)
app.secret_key = 'YourSecretKey'  # Replace with your secret key

# Your OAuth2 configuration details here
AUTHORIZATION_URL = "https://authserver/authorize"
ACCESS_TOKEN_URL = "https://authserver/token"
CLIENT_ID = 'YourClientId'  # Replace with your client ID
CLIENT_SECRET = 'YourClientSecret'  # Replace with your client secret
DOMAIN = '.yourdomain.com'  # Replace with the domain you wish to validate against
REDIRECT_URI = 'http://localhost:5000/redirect'  # Replace with your redirect URI
SCOPE = 'openid email profile'

@app.route('/')
def index():
    if 'access_token' in session:
        return 'You are already logged in.'
    else:
        return f'<a href="{AUTHORIZATION_URL}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&response_type=code&scope={SCOPE}">Log In</a>'

@app.route('/redirect')
def redirect():
    code = request.args.get('code', default=None, type=str)
    
    if not code:
        return 'Error: No authorization code received.'
        
    # Validate the redirect URI to ensure it matches our domain
    redirect_uri = request.args.get('redirect_uri', default='', type=str)
    if DOMAIN not in redirect_uri:
        return "Error: Redirect URI does not contain the configured domain."
    
    # Exchange authorization code for access token
    data = {
        'grant_type': 'authorization_code', 
        'client_id': CLIENT_ID, 
        'client_secret': CLIENT_SECRET, 
        'redirect_uri': REDIRECT_URI, 
        'code': code
    }
    
    response = requests.post(ACCESS_TOKEN_URL, data=data)
    
    if not response.ok:
        return f'Error: {response.text}'
        
    token_info = response.json()
    
    # Save the access token and other details to session for further use
    session['access_token'] = token_info['access_token']
    session['refresh_token'] = token_info.get('refresh_token', None)
    session['expires_in'] = token_info.get('expires_in', None)
    
    return 'You are now logged in.'

if __name__ == "__main__":
    app.run(port=5000, debug=True)